import random
import time

class Lift:
    def __init__(self, lift_id, num_floors):
        self.lift_id = lift_id
        self.current_floor = 1
        self.direction = 0  # 0: idle, 1: up, -1: down
        self.destination_floors = []
        self.num_floors = num_floors
        self.is_moving = False

    def add_destination(self, floor):
        if floor not in self.destination_floors:
            self.destination_floors.append(floor)
            self.destination_floors.sort(key=lambda x: (x - self.current_floor, abs(x - self.current_floor)))
            if len(self.destination_floors) == 1:
                if floor > self.current_floor:
                    self.direction = 1
                elif floor < self.current_floor:
                    self.direction = -1
                else:
                    self.direction = 0

    def move(self):
        if not self.destination_floors:
            self.direction = 0
            self.is_moving = False
            return

        self.is_moving = True

        if self.direction == 1:
            if self.current_floor < self.num_floors:
                self.current_floor += 1
            else:
                self.direction = -1
                self.current_floor -= 1
        elif self.direction == -1:
            if self.current_floor > 1:
                self.current_floor -= 1
            else:
                self.direction = 1
                self.current_floor += 1

        if self.current_floor in self.destination_floors:
            self.destination_floors.remove(self.current_floor)
            print(f"Lift {self.lift_id} arrived at floor {self.current_floor}")
            if not self.destination_floors:
                self.direction = 0
                self.is_moving = False
            else:
                next_destination = self.destination_floors[0]
                if next_destination > self.current_floor:
                    self.direction = 1
                elif next_destination < self.current_floor:
                    self.direction = -1
                else:
                    self.direction = 0

    def __repr__(self):
        return f"Lift {self.lift_id}: Floor {self.current_floor}, Direction {self.direction}, Destinations {self.destination_floors}"


class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.lifts = [Lift(i + 1, num_floors) for i in range(num_lifts)]

    def request_lift(self, start_floor, destination_floor):
        available_lifts = [lift for lift in self.lifts if not lift.is_moving]
        if available_lifts:
            closest_lift = min(available_lifts, key=lambda lift: abs(lift.current_floor - start_floor))
            print(f"Request: Floor {start_floor} to {destination_floor}. Assigning Lift {closest_lift.lift_id}")
            closest_lift.add_destination(start_floor)
            closest_lift.add_destination(destination_floor)
        else:
            moving_lifts = self.lifts
            closest_lift = min(moving_lifts, key=lambda lift: abs(lift.current_floor - start_floor))
            print(f"Request: Floor {start_floor} to {destination_floor}. Assigning Lift {closest_lift.lift_id}")
            closest_lift.add_destination(start_floor)
            closest_lift.add_destination(destination_floor)

    def step(self):
        for lift in self.lifts:
            lift.move()

    def display_state(self):
        for lift in self.lifts:
            print(lift)

def simulate(num_floors, num_lifts, crowd_size, duration):
    building = Building(num_floors, num_lifts)

    for t in range(duration):
        print(f"\n--- Time {t} ---")

        # Simulate requests based on time of day
        if 6 <= t < 9:  # Morning rush
            num_requests = int(crowd_size * 0.7 * random.random())
            for _ in range(num_requests):
                start_floor = random.randint(2, num_floors)
                destination_floor = 1
                building.request_lift(start_floor, destination_floor)
        elif 11 <= t < 13:  # Lunch rush
            num_requests = int(crowd_size * 0.4 * random.random())
            for _ in range(num_requests):
                start_floor = 1
                destination_floor = random.randint(2, num_floors)
                building.request_lift(start_floor, destination_floor)
        elif 16 <= t < 19:  # Evening rush
            num_requests = int(crowd_size * 0.8 * random.random())
            for _ in range(num_requests):
                start_floor = 1
                destination_floor = random.randint(2, num_floors)
                building.request_lift(start_floor, destination_floor)
        else:  # Random requests
            num_requests = int(crowd_size * 0.1 * random.random())
            for _ in range(num_requests):
                start_floor = random.randint(1, num_floors)
                destination_floor = random.randint(1, num_floors)
                while start_floor == destination_floor:
                    destination_floor = random.randint(1, num_floors)
                building.request_lift(start_floor, destination_floor)

        building.step()
        building.display_state()
        time.sleep(0.2)

if __name__ == "__main__":
    num_floors = 10
    num_lifts = 3
    crowd_size = 10
    duration = 24  # Simulate for 24 "hours"

    simulate(num_floors, num_lifts, crowd_size, duration)

import random
