class Lift:
    def __init__(self, lift_id, num_floors):
        self.lift_id = lift_id
        self.current_floor = 1
        self.direction = 0  # 0: idle, 1: up, -1: down
        self.destination_floors = []
        self.num_floors = num_floors
        self.is_busy = False

    def __repr__(self):
        return f"Lift {self.lift_id}: Floor {self.current_floor}, Direction {self.direction}, Destinations {self.destination_floors}, Busy: {self.is_busy}"

    def add_destination(self, floor):
        if floor not in self.destination_floors:
            self.destination_floors.append(floor)
            self.destination_floors.sort(key=lambda x: (x > self.current_floor, x)) # Sort destinations based on current floor and direction
            self.is_busy = True

    def move(self):
        if not self.destination_floors:
            self.direction = 0
            self.is_busy = False
            return

        next_destination = self.destination_floors[0]

        if self.current_floor < next_destination:
            self.direction = 1
            self.current_floor += 1
        elif self.current_floor > next_destination:
            self.direction = -1
            self.current_floor -= 1
        else:
            self.destination_floors.pop(0)
            print(f"Lift {self.lift_id}: Arrived at floor {self.current_floor}")

        if not self.destination_floors:
            self.direction = 0
            self.is_busy = False

class Building:
    def __init__(self, num_floors, num_lifts):
        self.num_floors = num_floors
        self.lifts = [Lift(i + 1, num_floors) for i in range(num_lifts)]
        self.requests = []

    def request_lift(self, start_floor, destination_floor):
        if not (1 <= start_floor <= self.num_floors and 1 <= destination_floor <= self.num_floors):
            print("Invalid floor request.")
            return

        self.requests.append((start_floor, destination_floor))
        print(f"Request: From floor {start_floor} to {destination_floor}")

    def assign_lift(self, start_floor, destination_floor):
        available_lifts = [lift for lift in self.lifts if not lift.is_busy]
        if available_lifts:
            closest_lift = min(available_lifts, key=lambda lift: abs(lift.current_floor - start_floor))
            closest_lift.add_destination(start_floor)
            closest_lift.add_destination(destination_floor)
            print(f"Assigned Lift {closest_lift.lift_id} to request from {start_floor} to {destination_floor}")
