        # Process requests
        while self.requests:
            start_floor, destination_floor = self.requests.pop(0)
            self.assign_lift(start_floor, destination_floor)

        # Move lifts
        for lift in self.lifts:
            lift.move()

    def display_state(self):
        for lift in self.lifts:
            print(lift)

