                building.request_lift(start_floor, destination_floor)

        # Simulate evening rush (hours 17-18)
        elif 17 <= hour < 18:
            num_requests = int(crowd_size * 0.6)
            for _ in range(num_requests):
                start_floor = random.randint(2, building.num_floors)
                destination_floor = 1  # People leaving to the lobby
                building.request_lift(start_floor, destination_floor)

        # Simulate nighttime activity (hours 18-22)
        elif 18 <= hour < 22:
            num_requests = int(crowd_size * 0.05)
