class Lift:
    def __init__(self, lift_id, num_floors):
        self.lift_id = lift_id
        self.current_floor = 1
        self.destination_floor = None
        self.direction = None  # "up", "down", or None
        self.passengers = []
        self.max_capacity = 10
        self.num_floors = num_floors

    def __repr__(self):
        return f"Lift {self.lift_id}: Floor {self.current_floor}, Dest: {self.destination_floor}, Dir: {self.direction}, Passengers: {len(self.passengers)}"

    def move(self):
        if self.destination_floor is None:
            return

        if self.current_floor < self.destination_floor:
            self.direction = "up"
            self.current_floor += 1
        elif self.current_floor > self.destination_floor:
            self.direction = "down"
            self.current_floor -= 1

        if self.current_floor == self.destination_floor:
            self.direction = None
            self.destination_floor = None
            self.passengers = [] # Simulate passengers exiting

    def call_lift(self, floor, direction):
        if self.destination_floor is None:
            self.destination_floor = floor
            return True
        else:
            return False # Lift is busy

class Building:
    def __init__(self, num_lifts, num_floors):
        self.num_lifts = num_lifts
        self.num_floors = num_floors
        self.lifts = [Lift(i + 1, num_floors) for i in range(num_lifts)]

    def request_lift(self, floor, direction):
        available_lifts = [lift for lift in self.lifts if lift.destination_floor is None]

        if not available_lifts:
            return None  # All lifts are busy

        # Find the closest available lift
        closest_lift = min(available_lifts, key=lambda lift: abs(lift.current_floor - floor))

        if closest_lift.call_lift(floor, direction):
            return closest_lift
        else:
            return None

    def simulate_step(self):
        for lift in self.lifts:
            lift.move()

    def display_state(self):
        for lift in self.lifts:
            print(lift)

