    building = Building(num_lifts, num_floors)

    for _ in range(duration):
        # Simulate passenger requests based on time of day
        hour = (_ % (24 * 60)) // 60  # Simulate time of day (hours)

        # Morning rush hour
        if 7 <= hour < 9:
            request_probability = 0.8 * crowd_size / 100
        # Evening rush hour
        elif 17 <= hour < 19:
            request_probability = 0.7 * crowd_size / 100
        # Lunch time
        elif 12 <= hour < 14:
            request_probability = 0.5 * crowd_size / 100
        # Night time
        elif 22 <= hour or hour < 6:
            request_probability = 0.05 * crowd_size / 100
        # Normal office hours
        else:
            request_probability = 0.2 * crowd_size / 100

        if random.random() < request_probability:
            floor = random.randint(1, num_floors)
            direction = random.choice(["up", "down"])
            building.request_lift(floor, direction)

        building.simulate_step()
        building.display_state()
        print("-" * 20)
