import random
import time

class Elevator:
    def __init__(self, elevator_id, num_floors):
        self.elevator_id = elevator_id
        self.current_floor = 1
        self.direction = 0  # 0: idle, 1: up, -1: down
        self.destination = None
        self.passengers = []
        self.num_floors = num_floors

    def __repr__(self):
        return f"Elevator {self.elevator_id}: Floor {self.current_floor}, Direction {self.direction}, Destination {self.destination}, Passengers {len(self.passengers)}"

    def move(self):
        if self.destination is None:
            self.direction = 0
            return

        if self.current_floor < self.destination:
            self.direction = 1
            self.current_floor += 1
        elif self.current_floor > self.destination:
            self.direction = -1
            self.current_floor -= 1
        else:
            self.direction = 0
            self.destination = None
            self.passengers = [] # Simulate passengers exiting

    def call_elevator(self, floor, direction):
        if self.direction == 0:
            self.destination = floor
            return True
        else:
            # Check if the elevator is going in the same direction and can pick up the passenger
            if (direction == 1 and self.direction == 1 and self.current_floor <= floor) or \
               (direction == -1 and self.direction == -1 and self.current_floor >= floor):
                # Check if the new floor is closer to the destination
                if self.direction == 1:
                    if self.destination is None or floor < self.destination:
                        self.destination = floor
                        return True
                else:
                    if self.destination is None or floor > self.destination:
                        self.destination = floor
                        return True
            return False

    def add_passenger(self, destination_floor):
        self.passengers.append(destination_floor)
        if self.direction == 0:
            self.destination = destination_floor
        elif self.direction == 1 and destination_floor > self.destination:
            self.destination = destination_floor
        elif self.direction == -1 and destination_floor < self.destination:
            self.destination = destination_floor

class Building:
    def __init__(self, num_elevators, num_floors):
        self.num_elevators = num_elevators
        self.num_floors = num_floors
        self.elevators = [Elevator(i + 1, num_floors) for i in range(num_elevators)]
        self.requests = [] # (floor, direction, destination)

    def generate_request(self, time_of_day):
        # Simulate different traffic patterns based on time of day
        if 6 <= time_of_day < 9:  # Morning rush hour
            origin_floor = random.randint(2, self.num_floors)
            destination_floor = 1
        elif 11 <= time_of_day < 14:  # Lunch time
            origin_floor = random.randint(1, self.num_floors)
            destination_floor = random.randint(1, self.num_floors)
            while destination_floor == origin_floor:
                destination_floor = random.randint(1, self.num_floors)
        elif 16 <= time_of_day < 19:  # Evening rush hour
            origin_floor = 1
            destination_floor = random.randint(2, self.num_floors)
        elif 20 <= time_of_day < 23: # Evening
            origin_floor = random.randint(1, self.num_floors)
            destination_floor = random.randint(1, self.num_floors)
            while destination_floor == origin_floor:
                destination_floor = random.randint(1, self.num_floors)
        else:  # Off-peak hours
            origin_floor = random.randint(1, self.num_floors)
            destination_floor = random.randint(1, self.num_floors)
            while destination_floor == origin_floor:
                destination_floor = random.randint(1, self.num_floors)

        direction = 1 if destination_floor > origin_floor else -1
        self.requests.append((origin_floor, direction, destination_floor))

    def assign_elevator(self, floor, direction, destination):
        available_elevators = []
        for elevator in self.elevators:
            if elevator.call_elevator(floor, direction):
                available_elevators.append(elevator)

        if available_elevators:
            # Assign the closest elevator
            closest_elevator = min(available_elevators, key=lambda e: abs(e.current_floor - floor))
            closest_elevator.add_passenger(destination)
            return True
        else:
            return False

    def run_simulation(self, duration, traffic_intensity):
        for time_of_day in range(duration):
            # Generate requests based on traffic intensity
            for _ in range(traffic_intensity):
                self.generate_request(time_of_day % 24)

            # Assign elevators to requests
            for request in list(self.requests):
                floor, direction, destination = request
                if self.assign_elevator(floor, direction, destination):
                    self.requests.remove(request)

            # Move elevators
            for elevator in self.elevators:
                elevator.move()

            # Print simulation state
            print(f"Time: {time_of_day}")
            for elevator in self.elevators:
                print(elevator)
            print(f"Unassigned requests: {len(self.requests)}")
            time.sleep(0.1) # Add a small delay for visualization

