class Passenger:
    def __init__(self, passenger_id, start_floor, destination_floor):
        self.passenger_id = passenger_id
        self.start_floor = start_floor
        self.destination_floor = destination_floor
        self.elevator_id = None

    def __repr__(self):
        return f"Passenger {self.passenger_id}: Start {self.start_floor}, Destination {self.destination_floor}, Elevator {self.elevator_id}"

def simulate_elevator(num_elevators, num_floors, simulation_duration, peak_hours):
    elevators = [Elevator(i + 1, num_floors) for i in range(num_elevators)]
    passengers = []
    passenger_id_counter = 1

    def generate_passenger():
        nonlocal passenger_id_counter
        start_floor = random.randint(1, num_floors)
        destination_floor = random.randint(1, num_floors)
        while destination_floor == start_floor:
            destination_floor = random.randint(1, num_floors)
        passenger = Passenger(passenger_id_counter, start_floor, destination_floor)
        passenger_id_counter += 1
        return passenger

    def get_available_elevator(floor):
        available_elevators = []
        for elevator in elevators:
            if elevator.direction == 0:
                available_elevators.append(elevator)
            elif elevator.direction == 1 and elevator.current_floor <= floor:
                available_elevators.append(elevator)
            elif elevator.direction == -1 and elevator.current_floor >= floor:
                available_elevators.append(elevator)

        if not available_elevators:
            return None

        return min(available_elevators, key=lambda elevator: abs(elevator.current_floor - floor))

    for time_step in range(simulation_duration):
        # Passenger generation based on time of day
        if time_step in peak_hours:
            passenger_generation_rate = 0.1 # Higher rate during peak hours
        elif 6 <= (time_step % 24) < 22:
            passenger_generation_rate = 0.05 # Daytime rate
        else:
            passenger_generation_rate = 0.01 # Nighttime rate

        if random.random() < passenger_generation_rate:
            passengers.append(generate_passenger())

