        elif self.current_floor > self.destination:
            self.direction = -1
            self.current_floor -= 1
        else:
            self.direction = 0
            self.destination = None
            return True # Reached destination

        return False # Not yet reached destination

    def add_passenger(self, passenger):
        self.passengers.append(passenger)

    def remove_passenger(self, passenger):
        self.passengers.remove(passenger)

class Passenger:
    def __init__(self, passenger_id, start_floor, destination_floor):
        self.passenger_id = passenger_id
        self.start_floor = start_floor
        self.destination_floor = destination_floor
        self.elevator_id = None

    def __repr__(self):
        return f"Passenger {self.passenger_id}: Start {self.start_floor}, Destination {self.destination_floor}, Elevator {self.elevator_id}"

def simulate_elevator(num_elevators, num_floors, simulation_duration, peak_hours):
    elevators = [Elevator(i + 1, num_floors) for i in range(num_elevators)]
    passengers = []
    passenger_id_counter = 1

    def generate_passenger():
        nonlocal passenger_id_counter
        start_floor = random.randint(1, num_floors)
        destination_floor = random.randint(1, num_floors)
        while destination_floor == start_floor:
            destination_floor = random.randint(1, num_floors)
        passenger = Passenger(passenger_id_counter, start_floor, destination_floor)
        passenger_id_counter += 1
        return passenger

    def get_available_elevator(floor):
        available_elevators = []
        for elevator in elevators:
            if elevator.direction == 0:
                available_elevators.append(elevator)
            elif elevator.direction == 1 and elevator.current_floor <= floor:
                available_elevators.append(elevator)
            elif elevator.direction == -1 and elevator.current_floor >= floor:
                available_elevators.append(elevator)

        if not available_elevators:
            return None

        return min(available_elevators, key=lambda elevator: abs(elevator.current_floor - floor))

    for time_step in range(simulation_duration):
        # Passenger generation based on time of day
        if time_step in peak_hours:
            passenger_generation_rate = 0.1 # Higher rate during peak hours
        elif 6 <= (time_step % 24) < 22:
            passenger_generation_rate = 0.05 # Daytime rate
        else:
            passenger_generation_rate = 0.01 # Nighttime rate

        if random.random() < passenger_generation_rate:
            passengers.append(generate_passenger())

        # Assign passengers to elevators
        for passenger in passengers:
            if passenger.elevator_id is None:
                elevator = get_available_elevator(passenger.start_floor)
                if elevator:
                    elevator.destination = passenger.start_floor
                    passenger.elevator_id = elevator.elevator_id

        # Move elevators
        for elevator in elevators:
            reached_destination = elevator.move()

            # Pick up passengers
            if elevator.current_floor == elevator.destination:
                for passenger in passengers:
                    if passenger.elevator_id == elevator.elevator_id and passenger.start_floor == elevator.current_floor:
                        elevator.add_passenger(passenger)
                        elevator.destination = passenger.destination_floor

            # Drop off passengers
            passengers_to_remove = []
            for passenger in elevator.passengers:
                if elevator.current_floor == passenger.destination_floor:
                    passengers_to_remove.append(passenger)

            for passenger in passengers_to_remove:
                elevator.remove_passenger(passenger)
                passengers.remove(passenger)

        # Print simulation state (optional)
        # print(f"Time Step: {time_step}")
        # for elevator in elevators:
        #     print(elevator)
        # for passenger in passengers:
        #     print(passenger)
        # print("-" * 20)
        # time.sleep(0.1)

    print("Simulation complete.")

if __name__ == "__main__":
    num_elevators = 3
    num_floors = 10
    simulation_duration = 24 * 60 # Simulate for 24 hours (in minutes)
    peak_hours = list(range(8*60, 10*60)) + list(range(17*60, 19*60)) # 8-10am and 5-7pm

    simulate_elevator(num_elevators, num_floors, simulation_duration, peak_hours)

